import base64
import os

# Base64 encoded simple black squares with white text (192x192 and 512x512)
icon_192 = b''

icon_512 = b''

output_dir = "d:/專案/GFmoter/frontend/public"
os.makedirs(output_dir, exist_ok=True)

with open(os.path.join(output_dir, "pwa-192x192.png"), "wb") as f:
    f.write(base64.b64decode(icon_192))
    
with open(os.path.join(output_dir, "pwa-512x512.png"), "wb") as f:
    f.write(base64.b64decode(icon_512))

print("Placeholder icons created successfully.")
